INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-1', 'implemented', 'Patriot Health Systems has developed and maintains Access Control Policy PHS-POL-AC-001 v4.0 governing all access to the MFEHR system. The policy addresses account management, access enforcement, information flow, separation of duties, least privilege, remote access, wireless access, and mobile device controls. Procedures are documented in PHS-PROC-AC-001 v3.1. The Dr. James Whitfield reviews and updates the policy annually, with the most recent review completed January 2026. All personnel with MFEHR access acknowledge the policy during onboarding and annually thereafter.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-11', 'implemented', 'Patriot Health Systems enforces AC-11 within the MFEHR system boundary using Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users for authentication and authorization. Access control policies defined in PHS-POL-AC-001 specify requirements for AC-11. Technical enforcement is provided through AWS GovCloud (US-East) security controls and AWS Network Firewall with Palo Alto VM-Series. The Sarah Rodriguez monitors compliance through Splunk Enterprise dashboards and conducts quarterly access reviews per PHS-PROC-AC-REVIEW-001.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-11","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-11(1)', 'implemented', 'Patriot Health Systems implements AC-11(1) for the MFEHR system. This enhancement to AC-11 is enforced through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users with additional technical controls provided by AWS GovCloud (US-East). The ISSO ensures configuration compliance through SCCM for configuration management and STIG enforcement. Implementation details are documented in PHS-PROC-AC-11(1) and verified during quarterly security assessments. All relevant activities are monitored by Splunk Enterprise.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-111","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
