INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-2', 'implemented', 'Account management for MFEHR is performed through Okta with automated provisioning and deprovisioning workflows. New accounts require supervisor approval via ServiceNow workflow. Sarah Rodriguez conducts access reviews every 90 days using automated reports from Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users. Accounts inactive for 45 days are automatically disabled. Terminated users are deprovisioned within 24 hours per HR integration. All account lifecycle events are logged to Splunk Enterprise for audit purposes. Emergency accounts require AO approval and are limited to 72-hour validity.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-2(1)', 'implemented', 'Patriot Health Systems implements AC-2(1) for the MFEHR system. This enhancement to AC-2 is enforced through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users with additional technical controls provided by AWS GovCloud (US-East). The ISSO ensures configuration compliance through SCCM for configuration management and STIG enforcement. Implementation details are documented in PHS-PROC-AC-2(1) and verified during quarterly security assessments. All relevant activities are monitored by Splunk Enterprise.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-21","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-2(13)', 'partially_implemented', 'Patriot Health Systems has partially implemented AC-2(13) for the MFEHR system. Core access control mechanisms are operational through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users, enforcing role-based access with least privilege principles. However, automated access review workflows for AC-2(13) requirements are still being configured in ServiceNow. The Sarah Rodriguez conducts manual quarterly reviews as an interim measure. Full automation is targeted for completion by Q3 FY2026, tracked in POA&M item POAM-MFEHR-2026-AC2. Current policy documentation exists in PHS-POL-AC-001 v2.1.', 'ISSO', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-213","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
