INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-20(2)', 'implemented', 'Patriot Health Systems implements AC-20(2) for the MFEHR system. This enhancement to AC-20 is enforced through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users with additional technical controls provided by AWS GovCloud (US-East). The ISSO ensures configuration compliance through SCCM for configuration management and STIG enforcement. Implementation details are documented in PHS-PROC-AC-20(2) and verified during quarterly security assessments. All relevant activities are monitored by Splunk Enterprise.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-202","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-21', 'partially_implemented', 'Patriot Health Systems has partially implemented AC-21 for the MFEHR system. Core access control mechanisms are operational through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users, enforcing role-based access with least privilege principles. However, automated access review workflows for AC-21 requirements are still being configured in ServiceNow. The Sarah Rodriguez conducts manual quarterly reviews as an interim measure. Full automation is targeted for completion by Q3 FY2026, tracked in POA&M item POAM-MFEHR-2026-AC21. Current policy documentation exists in PHS-POL-AC-001 v2.1.', 'ISSO', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-21","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-22', 'implemented', 'Patriot Health Systems enforces AC-22 within the MFEHR system boundary using Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users for authentication and authorization. Access control policies defined in PHS-POL-AC-001 specify requirements for AC-22. Technical enforcement is provided through AWS GovCloud (US-East) security controls and AWS Network Firewall with Palo Alto VM-Series. The Sarah Rodriguez monitors compliance through Splunk Enterprise dashboards and conducts quarterly access reviews per PHS-PROC-AC-REVIEW-001.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-22","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-3', 'implemented', 'Access enforcement in MFEHR uses role-based access control (RBAC) with eight defined role tiers. Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users enforces authentication requirements before granting access. Amazon RDS PostgreSQL 15 (encrypted with AWS KMS CMK) implements row-level security for data isolation between organizational units. All access decisions are logged to Splunk Enterprise. API endpoints enforce authorization checks using middleware that validates JWT claims against role permissions. Administrative access requires additional MFA step-up authentication.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-3","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AC-4', 'implemented', 'Information flow enforcement within MFEHR is implemented through AWS Network Firewall with Palo Alto VM-Series rules that restrict data movement between security domains. AWS GovCloud (US-East) network segmentation isolates PHI, CUI, PII, and medical records processing from public-facing components. Data loss prevention rules in AWS Network Firewall with Palo Alto VM-Series prevent unauthorized transmission of PHI, CUI, PII, and medical records. All cross-boundary data flows are logged and monitored by Splunk Enterprise.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AC-001, PHS-PROC-AC-4","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
