INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AU-1', 'implemented', 'Patriot Health Systems has established Audit and Accountability Policy PHS-POL-AU-001 v3.0 for the MFEHR system. The policy defines auditable events, audit record content requirements, audit storage capacity, audit review and analysis procedures, and audit record retention (365 days minimum). Procedures are documented in PHS-PROC-AU-001. The Security Engineer maintains audit infrastructure on AWS GovCloud (US-East) with events forwarded to Splunk Enterprise.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AU-001, PHS-PROC-AU-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AU-11', 'implemented', 'Patriot Health Systems implements AU-11 for the MFEHR system. Splunk Enterprise provides centralized audit management with automated collection from AWS GovCloud (US-East) infrastructure, Amazon RDS PostgreSQL 15 (encrypted with AWS KMS CMK) audit logs, and application event streams. Audit records include timestamp, source, event type, user identity, outcome, and affected resources. The Security Engineer reviews audit configurations quarterly per PHS-PROC-AU-001. Audit data is retained for 365 days with integrity protections.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AU-001, PHS-PROC-AU-11","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AU-12', 'implemented', 'MFEHR generates audit records for all events defined in AU-2 at each processing component. AWS GovCloud (US-East) infrastructure generates platform-level audit records. Application code generates structured audit entries for business logic events. Amazon RDS PostgreSQL 15 (encrypted with AWS KMS CMK) generates query audit logs. All audit generation is configured per PHS-PROC-AU-012 and validated monthly by the Security Engineer. Audit generation cannot be disabled without Sarah Rodriguez approval and change control via ServiceNow.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AU-001, PHS-PROC-AU-12","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'AU-2', 'implemented', 'MFEHR logs all auditable events across all system tiers: application events (authentication, authorization decisions, data access, configuration changes), infrastructure events from AWS GovCloud (US-East), database audit logs from Amazon RDS PostgreSQL 15 (encrypted with AWS KMS CMK), and network events from AWS Network Firewall with Palo Alto VM-Series. Event types are reviewed annually and updated based on threat intelligence. All events are forwarded to Splunk Enterprise within 60 seconds for real-time correlation and alerting. The Security Engineer maintains the audit event catalog in PHS-PROC-AU-002.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-AU-001, PHS-PROC-AU-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
