INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CM-1', 'implemented', 'Patriot Health Systems has established Configuration Management Policy PHS-POL-CM-001 v3.0 for the MFEHR system. The policy covers baseline configurations, change management, security impact analysis, access restrictions for change, least functionality, and configuration settings. SCCM for configuration management and STIG enforcement enforces baselines across AWS GovCloud (US-East) infrastructure. The System Administrator maintains the CM program with Sarah Rodriguez oversight. Procedures documented in PHS-PROC-CM-001.', 'System Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-CM-001, PHS-PROC-CM-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CM-10', 'partially_implemented', 'Configuration management for CM-10 is partially implemented in the MFEHR environment. SCCM for configuration management and STIG enforcement enforces baseline configurations across managed components on AWS GovCloud (US-East). However, automated deviation detection and remediation workflows for all CM-10 sub-requirements are still being validated. The DevOps Engineering Team performs weekly manual configuration audits as a compensating measure. Full implementation is tracked in POA&M POAM-MFEHR-2026-CM10 with target completion Q3 FY2026.', 'System Administrator', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-CM-001, PHS-PROC-CM-10","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CM-11', 'partially_implemented', 'Configuration management for CM-11 is partially implemented in the MFEHR environment. SCCM for configuration management and STIG enforcement enforces baseline configurations across managed components on AWS GovCloud (US-East). However, automated deviation detection and remediation workflows for all CM-11 sub-requirements are still being validated. The DevOps Engineering Team performs weekly manual configuration audits as a compensating measure. Full implementation is tracked in POA&M POAM-MFEHR-2026-CM11 with target completion Q3 FY2026.', 'System Administrator', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-CM-001, PHS-PROC-CM-11","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CM-12', 'planned', 'Implementation of CM-12 for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-CM12-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-CM12 with monthly status reviews by the Sarah Rodriguez.', 'System Administrator', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-CM-001, PHS-PROC-CM-12","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CM-12(1)', 'planned', 'Implementation of CM-12(1) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-CM12-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-CM121 with monthly status reviews by the Sarah Rodriguez.', 'System Administrator', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-CM-001, PHS-PROC-CM-121","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CM-2', 'implemented', 'Security configuration baselines for MFEHR are established and maintained using SCCM for configuration management and STIG enforcement. Baselines cover AWS GovCloud (US-East) infrastructure, Amazon RDS PostgreSQL 15 (encrypted with AWS KMS CMK) configurations, application settings, and network device configurations from AWS Network Firewall with Palo Alto VM-Series. Baseline deviations require change control approval via ServiceNow with security impact analysis. The System Administrator reviews and updates baselines quarterly. Current baselines are documented in PHS-PROC-CM-002.', 'System Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-CM-001, PHS-PROC-CM-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
