INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CP-10', 'implemented', 'Patriot Health Systems implements CP-10 for the MFEHR system as part of its business continuity program. AWS GovCloud (US-East) provides infrastructure-level resilience with automatic failover capabilities. The Contingency Planning Coordinator maintains recovery procedures in PHS-PROC-CP-10 and coordinates annual testing. Recovery objectives are: RTO of 4 hours and RPO of 1 hour for PHI, CUI, PII, and medical records.', 'Contingency Planning Coordinator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-CP-001, PHS-PROC-CP-10","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
