INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CP-2(8)', 'planned', 'Implementation of CP-2(8) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-CP2-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-CP28 with monthly status reviews by the Sarah Rodriguez.', 'Contingency Planning Coordinator', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-CP-001, PHS-PROC-CP-28","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
