INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CP-9', 'implemented', 'MFEHR data backups are performed automatically by Amazon RDS PostgreSQL 15 (encrypted with AWS KMS CMK) with the following schedule: full backups daily (retained 30 days), incremental backups every 6 hours, and transaction log backups every 15 minutes. Backups are encrypted using AES-256 and stored in a geographically separate region. Backup integrity is verified weekly through automated restore testing. The System Administrator monitors backup completion via Splunk Enterprise alerts.', 'Contingency Planning Coordinator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-CP-001, PHS-PROC-CP-9","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CP-9(1)', 'partially_implemented', 'Contingency planning control CP-9(1) for MFEHR is partially addressed. Core disaster recovery procedures are documented in PHS-POL-CP-001, and AWS GovCloud (US-East) provides infrastructure-level redundancy. Testing of the full CP-9(1) requirements, including tabletop exercises and functional recovery tests, has been partially completed. The Contingency Planning Coordinator is scheduling additional tests per PHS-PROC-CP-TEST-001. POA&M POAM-MFEHR-2026-CP9 tracks remaining items.', 'Contingency Planning Coordinator', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-CP-001, PHS-PROC-CP-91","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'CP-9(8)', 'planned', 'Implementation of CP-9(8) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-CP9-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-CP98 with monthly status reviews by the Sarah Rodriguez.', 'Contingency Planning Coordinator', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-CP-001, PHS-PROC-CP-98","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-1', 'implemented', 'Patriot Health Systems maintains Identification and Authentication Policy PHS-POL-IA-001 v3.0 for the MFEHR system. The policy establishes requirements for user identification, authenticator management, MFA, device identification, and federated identity. Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users serves as the primary identity provider. The Identity Administrator manages the IA infrastructure. Procedures documented in PHS-PROC-IA-001.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-11', 'partially_implemented', 'Identity and authentication control IA-11 for MFEHR is partially implemented. Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users provides primary authentication with MFA enforcement for all privileged and non-privileged users. Specific IA-11 enhancements requiring additional identity proofing or federation capabilities are in progress. Okta configuration updates are being tested in the staging environment by the Identity Administrator. Target completion is Q3 FY2026, tracked in POA&M POAM-MFEHR-2026-IA11.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-11","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-12', 'implemented', 'Patriot Health Systems implements IA-12 for the MFEHR system through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users and Okta. Authentication policies enforce password complexity (16-character minimum, no dictionary words), account lockout (5 attempts), and session management. The Identity Administrator reviews authentication configurations quarterly. All authentication events are logged to Splunk Enterprise for security monitoring.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-12","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-12(2)', 'planned', 'Implementation of IA-12(2) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-IA12-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-IA122 with monthly status reviews by the Sarah Rodriguez.', 'Identity Administrator', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-122","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-12(3)', 'planned', 'Implementation of IA-12(3) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-IA12-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-IA123 with monthly status reviews by the Sarah Rodriguez.', 'Identity Administrator', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-123","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-12(5)', 'planned', 'Implementation of IA-12(5) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-IA12-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-IA125 with monthly status reviews by the Sarah Rodriguez.', 'Identity Administrator', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-125","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-2', 'implemented', 'All MFEHR users are uniquely identified and authenticated through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users. Network and local access requires valid credentials verified against the Okta identity store. Session tokens are cryptographically signed and expire after 8 hours of inactivity. Failed authentication attempts are logged to Splunk Enterprise and accounts are locked after 5 consecutive failures. The Identity Administrator manages user provisioning per PHS-PROC-IA-002.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-2(1)', 'implemented', 'MFEHR enforces multi-factor authentication for all privileged access through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users. Privileged users must present a valid password plus a second factor (hardware token or authenticator application) before accessing administrative functions. MFA is enforced at the Okta level and cannot be bypassed. MFA configuration is documented in PHS-PROC-IA-002-01 and audited quarterly.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-21","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IA-2(12)', 'implemented', 'Patriot Health Systems implements IA-2(12) for the MFEHR system through Okta SSO with FIDO2/PIV MFA, Azure AD federation for VA users and Okta. Authentication policies enforce password complexity (16-character minimum, no dictionary words), account lockout (5 attempts), and session management. The Identity Administrator reviews authentication configurations quarterly. All authentication events are logged to Splunk Enterprise for security monitoring.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IA-001, PHS-PROC-IA-212","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
