INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IR-1', 'implemented', 'Patriot Health Systems maintains Incident Response Policy PHS-POL-IR-001 v3.0 for the MFEHR system. The policy establishes the incident response program including preparation, detection and analysis, containment, eradication, recovery, and post-incident activities. The Incident Response Lead coordinates the program with 24/7 coverage via soc@patriothealth.com. Procedures documented in PHS-PROC-IR-001, reviewed annually.', 'Incident Response Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IR-001, PHS-PROC-IR-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IR-2', 'implemented', 'Patriot Health Systems implements IR-2 for the MFEHR system as part of its incident response program. Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints provides detection capabilities with automated alerting to soc@patriothealth.com. The Incident Response Lead coordinates response activities per PHS-PROC-IR-2. Incident metrics are reported to the Dr. James Whitfield monthly and used to improve detection and response procedures.', 'Incident Response Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IR-001, PHS-PROC-IR-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IR-3', 'implemented', 'Patriot Health Systems implements IR-3 for the MFEHR system as part of its incident response program. Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints provides detection capabilities with automated alerting to soc@patriothealth.com. The Incident Response Lead coordinates response activities per PHS-PROC-IR-3. Incident metrics are reported to the Dr. James Whitfield monthly and used to improve detection and response procedures.', 'Incident Response Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IR-001, PHS-PROC-IR-3","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IR-3(2)', 'planned', 'Implementation of IR-3(2) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-IR3-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-IR32 with monthly status reviews by the Sarah Rodriguez.', 'Incident Response Lead', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-IR-001, PHS-PROC-IR-32","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IR-4', 'implemented', 'MFEHR incident handling follows the process defined in PHS-PROC-IR-004: (1) Detection via Splunk Enterprise and CrowdStrike Falcon automated alerts, (2) Triage by SOC analysts within 15 minutes, (3) Containment actions per severity-specific playbooks, (4) Eradication and recovery with change control, (5) Lessons learned within 5 business days. All incidents are tracked in ServiceNow with classification per PHS-POL-IR-001. The Incident Response Lead briefs Dr. James Whitfield on significant incidents within 1 hour.', 'Incident Response Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-IR-001, PHS-PROC-IR-4","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'IR-4(1)', 'partially_implemented', 'Incident response capability for IR-4(1) within MFEHR is partially operational. Patriot Health Systems maintains an incident response plan (PHS-POL-IR-001 v3.0) with defined procedures for detection, containment, and recovery. Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints provides real-time alerting to soc@patriothealth.com. However, specific IR-4(1) requirements for automated response orchestration are still being integrated. The Incident Response Lead is coordinating with DevOps Engineering Team to complete automation. POA&M POAM-MFEHR-2026-IR4 tracks this item.', 'Incident Response Lead', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-IR-001, PHS-PROC-IR-41","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
