INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'MA-3', 'alternative', 'Patriot Health Systems implements an alternative control for MA-3 within the MFEHR system boundary. The original control requirement is addressed through compensating controls documented in PHS-POL-ALT-MA3 and approved by the VA Authorizing Official. The compensating control provides equivalent or greater protection through Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints continuous monitoring and automated enforcement via AWS Network Firewall with Palo Alto VM-Series. Risk acceptance for this alternative implementation was signed by the AO on the most recent authorization date.', 'System Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-MA-001, PHS-PROC-MA-3","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
