INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'PL-1', 'implemented', 'Patriot Health Systems maintains Planning Policy PHS-POL-PL-001 v2.0 for the MFEHR system. The policy establishes requirements for system security plans, rules of behavior, security architecture, and information security workforce development. The Dr. James Whitfield reviews and updates the policy annually. Procedures are documented in PHS-PROC-PL-001.', 'Dr. James Whitfield', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-PL-001, PHS-PROC-PL-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'PL-10', 'partially_implemented', 'Patriot Health Systems has partially implemented PL-10 for the MFEHR system. Core requirements are operational, with specific sub-requirements under active development. Implementation progress is tracked in POA&M item POAM-MFEHR-2026-PL10. The Sarah Rodriguez reviews implementation status monthly. Policy documentation exists in PHS-POL-PL-001. Full implementation is targeted for Q3 FY2026 with DevOps Engineering Team leading the technical effort on AWS GovCloud (US-East).', 'Dr. James Whitfield', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-PL-001, PHS-PROC-PL-10","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
