INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'PL-2', 'implemented', 'The MFEHR System Security Plan (SSP) is maintained by the Sarah Rodriguez and documents the system boundary, operating environment, security categorization, control implementations, and interconnections. The SSP is reviewed and updated at least annually or upon significant system changes. The current SSP version addresses all 287 FedRAMP Moderate baseline controls. The SSP is stored in the MFEHR authorization package and available for VA Authorizing Official review.', 'Dr. James Whitfield', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-PL-001, PHS-PROC-PL-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'PL-4', 'implemented', 'Patriot Health Systems implements PL-4 for the MFEHR system. The Dr. James Whitfield oversees planning activities with the Sarah Rodriguez responsible for day-to-day security planning. Planning documents are maintained in the MFEHR authorization package and reviewed annually. Implementation details documented in PHS-PROC-PL-4.', 'Dr. James Whitfield', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-PL-001, PHS-PROC-PL-4","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'PL-4(1)', 'implemented', 'Patriot Health Systems implements PL-4(1) for the MFEHR system. The Dr. James Whitfield oversees planning activities with the Sarah Rodriguez responsible for day-to-day security planning. Planning documents are maintained in the MFEHR authorization package and reviewed annually. Implementation details documented in PHS-PROC-PL-4.', 'Dr. James Whitfield', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-PL-001, PHS-PROC-PL-41","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'PL-8', 'partially_implemented', 'Patriot Health Systems has partially implemented PL-8 for the MFEHR system. Core requirements are operational, with specific sub-requirements under active development. Implementation progress is tracked in POA&M item POAM-MFEHR-2026-PL8. The Sarah Rodriguez reviews implementation status monthly. Policy documentation exists in PHS-POL-PL-001. Full implementation is targeted for Q3 FY2026 with DevOps Engineering Team leading the technical effort on AWS GovCloud (US-East).', 'Dr. James Whitfield', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-PL-001, PHS-PROC-PL-8","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'PS-1', 'implemented', 'Patriot Health Systems maintains Personnel Security Policy PHS-POL-PS-001 v2.0. The policy establishes requirements for position risk designation, personnel screening, personnel termination and transfer, access agreements, third-party personnel security, and personnel sanctions. HR Security Liaison coordinates with the Sarah Rodriguez on personnel security matters. Procedures documented in PHS-PROC-PS-001, reviewed annually.', 'HR Security Liaison', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-PS-001, PHS-PROC-PS-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'PS-2', 'implemented', 'Patriot Health Systems implements PS-2 through its personnel security program documented in PHS-POL-PS-001. Personnel with access to MFEHR and PHI, CUI, PII, and medical records undergo background investigations commensurate with position risk designation. The HR Security Liaison coordinates with the Sarah Rodriguez on access agreements, transfers, and terminations. Personnel actions affecting system access are processed within 24 hours through ServiceNow workflows.', 'HR Security Liaison', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-PS-001, PHS-PROC-PS-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
