INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'RA-1', 'implemented', 'Patriot Health Systems maintains Risk Assessment Policy PHS-POL-RA-001 v2.0 for the MFEHR system. The policy establishes requirements for security categorization, risk assessments, vulnerability scanning, and risk response. The Risk Assessment Lead coordinates annual risk assessments with input from the Sarah Rodriguez and system owners. Procedures documented in PHS-PROC-RA-001.', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-RA-001, PHS-PROC-RA-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'RA-2', 'implemented', 'Patriot Health Systems implements RA-2 for the MFEHR system as part of its risk management program. Risk assessments are conducted annually and upon significant system changes. Tenable Nessus Professional provides technical vulnerability data, while threat intelligence from Splunk Enterprise informs risk prioritization. The Risk Assessment Lead maintains the risk register and reports findings to the Dr. James Whitfield. Documentation maintained in PHS-PROC-RA-2.', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-RA-001, PHS-PROC-RA-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'RA-3', 'implemented', 'Patriot Health Systems implements RA-3 for the MFEHR system as part of its risk management program. Risk assessments are conducted annually and upon significant system changes. Tenable Nessus Professional provides technical vulnerability data, while threat intelligence from Splunk Enterprise informs risk prioritization. The Risk Assessment Lead maintains the risk register and reports findings to the Dr. James Whitfield. Documentation maintained in PHS-PROC-RA-3.', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-RA-001, PHS-PROC-RA-3","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'RA-3(1)', 'partially_implemented', 'Patriot Health Systems has partially implemented RA-3(1) for the MFEHR system. Core requirements are operational, with specific sub-requirements under active development. Implementation progress is tracked in POA&M item POAM-MFEHR-2026-RA3. The Sarah Rodriguez reviews implementation status monthly. Policy documentation exists in PHS-POL-RA-001. Full implementation is targeted for Q3 FY2026 with DevOps Engineering Team leading the technical effort on AWS GovCloud (US-East).', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-RA-001, PHS-PROC-RA-31","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'RA-5', 'implemented', 'Vulnerability scanning for MFEHR is performed using Tenable Nessus Professional on the following schedule: authenticated scans of all system components weekly, web application scans monthly, and ad-hoc scans within 72 hours of new vulnerability disclosures. Scan results are correlated with threat intelligence in Splunk Enterprise. Critical vulnerabilities are remediated within 30 days, high within 90 days per PHS-PROC-RA-005. The Risk Assessment Lead reviews scan reports and tracks remediation in ServiceNow.', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-RA-001, PHS-PROC-RA-5","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'RA-5(11)', 'planned', 'Implementation of RA-5(11) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-RA5-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-RA511 with monthly status reviews by the Sarah Rodriguez.', 'Risk Assessment Lead', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-RA-001, PHS-PROC-RA-511","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
