INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-1', 'implemented', 'Patriot Health Systems maintains System and Communications Protection Policy PHS-POL-SC-001 v3.0 for the MFEHR system. The policy addresses boundary protection, transmission confidentiality, cryptographic protections, denial of service protection, and session management. The Network Security Engineer implements technical controls on AWS GovCloud (US-East) with AWS Network Firewall with Palo Alto VM-Series. Procedures documented in PHS-PROC-SC-001, reviewed annually.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-10', 'implemented', 'Patriot Health Systems implements SC-10 for the MFEHR system. AWS Network Firewall with Palo Alto VM-Series and AWS GovCloud (US-East) security features provide network-level protections. Cryptographic controls use FIPS 140-2 validated modules for PHI, CUI, PII, and medical records protection. The Network Security Engineer maintains SC controls per PHS-PROC-SC-10 with configurations validated through SCCM for configuration management and STIG enforcement compliance scans.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-10","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
