INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-17', 'partially_implemented', 'Patriot Health Systems has partially implemented SC-17 for the MFEHR system. Core requirements are operational, with specific sub-requirements under active development. Implementation progress is tracked in POA&M item POAM-MFEHR-2026-SC17. The Sarah Rodriguez reviews implementation status monthly. Policy documentation exists in PHS-POL-SC-001. Full implementation is targeted for Q3 FY2026 with DevOps Engineering Team leading the technical effort on AWS GovCloud (US-East).', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-17","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-18', 'alternative', 'Patriot Health Systems implements an alternative control for SC-18 within the MFEHR system boundary. The original control requirement is addressed through compensating controls documented in PHS-POL-ALT-SC18 and approved by the VA Authorizing Official. The compensating control provides equivalent or greater protection through Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints continuous monitoring and automated enforcement via AWS Network Firewall with Palo Alto VM-Series. Risk acceptance for this alternative implementation was signed by the AO on the most recent authorization date.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-18","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
