INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-23', 'partially_implemented', 'Patriot Health Systems has partially implemented SC-23 for the MFEHR system. Core requirements are operational, with specific sub-requirements under active development. Implementation progress is tracked in POA&M item POAM-MFEHR-2026-SC23. The Sarah Rodriguez reviews implementation status monthly. Policy documentation exists in PHS-POL-SC-001. Full implementation is targeted for Q3 FY2026 with DevOps Engineering Team leading the technical effort on AWS GovCloud (US-East).', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-23","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-28', 'implemented', 'MFEHR protects PHI, CUI, PII, and medical records at rest using Amazon RDS PostgreSQL 15 (encrypted with AWS KMS CMK) native encryption (AES-256). Encryption keys are managed through the cloud provider''s key management service with annual key rotation. Backup data is encrypted using separate encryption keys. The Network Security Engineer validates encryption configurations quarterly. Encryption status is monitored through Splunk Enterprise compliance dashboards.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-28","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
