INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-7', 'implemented', 'MFEHR boundary protection is implemented through AWS Network Firewall with Palo Alto VM-Series with deny-all, permit-by-exception rules. Network segmentation isolates PHI, CUI, PII, and medical records processing, management interfaces, and public-facing services. All inbound traffic is inspected for malicious content. Outbound traffic is filtered to prevent data exfiltration. Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints provides real-time visibility into boundary traffic. The Network Security Engineer reviews firewall rules quarterly per PHS-PROC-SC-007.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-7","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
