INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-7(8)', 'planned', 'Implementation of SC-7(8) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-SC7-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-SC78 with monthly status reviews by the Sarah Rodriguez.', 'Network Security Engineer', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-78","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-8', 'implemented', 'MFEHR protects transmitted PHI, CUI, PII, and medical records using TLS 1.3 for all external communications. HSTS headers enforce encrypted connections with a minimum 1-year max-age directive. Internal service-to-service communication uses mutual TLS (mTLS) with certificate validation. Certificate management is automated through AWS GovCloud (US-East) certificate services. The Network Security Engineer monitors certificate expiration and TLS configuration compliance via Splunk Enterprise.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-8","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SC-8(1)', 'implemented', 'Patriot Health Systems implements SC-8(1) for the MFEHR system. AWS Network Firewall with Palo Alto VM-Series and AWS GovCloud (US-East) security features provide network-level protections. Cryptographic controls use FIPS 140-2 validated modules for PHI, CUI, PII, and medical records protection. The Network Security Engineer maintains SC controls per PHS-PROC-SC-8 with configurations validated through SCCM for configuration management and STIG enforcement compliance scans.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SC-001, PHS-PROC-SC-81","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-1', 'implemented', 'Patriot Health Systems maintains System and Information Integrity Policy PHS-POL-SI-001 v3.0 for the MFEHR system. The policy covers flaw remediation, malicious code protection, information system monitoring, security alerts, software and information integrity, and spam protection. The Security Engineer implements technical controls. Procedures documented in PHS-PROC-SI-001, reviewed annually by the Dr. James Whitfield.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-1","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-10', 'partially_implemented', 'System and information integrity control SI-10 for MFEHR is partially operational. CrowdStrike Falcon provides malicious code protection and Tenable Nessus Professional performs regular vulnerability scanning across AWS GovCloud (US-East) components. Specific SI-10 requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in PHS-PROC-SI-001. POA&M POAM-MFEHR-2026-SI10 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-10","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-11', 'partially_implemented', 'System and information integrity control SI-11 for MFEHR is partially operational. CrowdStrike Falcon provides malicious code protection and Tenable Nessus Professional performs regular vulnerability scanning across AWS GovCloud (US-East) components. Specific SI-11 requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in PHS-PROC-SI-001. POA&M POAM-MFEHR-2026-SI11 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-11","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-12', 'partially_implemented', 'System and information integrity control SI-12 for MFEHR is partially operational. CrowdStrike Falcon provides malicious code protection and Tenable Nessus Professional performs regular vulnerability scanning across AWS GovCloud (US-East) components. Specific SI-12 requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in PHS-PROC-SI-001. POA&M POAM-MFEHR-2026-SI12 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-12","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-16', 'implemented', 'Patriot Health Systems implements SI-16 for the MFEHR system. CrowdStrike Falcon and Splunk Enterprise provide defense-in-depth for system integrity. Tenable Nessus Professional validates system integrity through regular scans. The Security Engineer maintains SI controls per PHS-PROC-SI-16 and reports findings to the Sarah Rodriguez. All integrity events are logged to Splunk Enterprise for continuous monitoring.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-16","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-2', 'implemented', 'Flaw remediation for MFEHR follows the patching schedule in PHS-PROC-SI-002: critical patches within 30 days, high within 60 days, moderate within 90 days. Tenable Nessus Professional identifies vulnerabilities and SCCM for configuration management and STIG enforcement deploys patches to AWS GovCloud (US-East) components. The Security Engineer validates patch deployment through compliance scans. Emergency patches follow the expedited change control process in ServiceNow. Patch status is reported to the Sarah Rodriguez weekly.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-2","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-2(2)', 'partially_implemented', 'System and information integrity control SI-2(2) for MFEHR is partially operational. CrowdStrike Falcon provides malicious code protection and Tenable Nessus Professional performs regular vulnerability scanning across AWS GovCloud (US-East) components. Specific SI-2(2) requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in PHS-PROC-SI-001. POA&M POAM-MFEHR-2026-SI2 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-22","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-3', 'implemented', 'Malicious code protection for MFEHR is provided by CrowdStrike Falcon deployed on all endpoints and servers. Signature updates are applied automatically within 4 hours of release. Real-time scanning covers file access, email attachments, and web downloads. CrowdStrike Falcon behavioral analysis detects zero-day threats. Alerts are forwarded to Splunk Enterprise for correlation. The Security Engineer reviews malware detection events daily per PHS-PROC-SI-003.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-3","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-4', 'implemented', 'MFEHR information system monitoring is implemented through Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints. Splunk Enterprise performs real-time event correlation with custom detection rules for PHI, CUI, PII, and medical records protection scenarios. CrowdStrike Falcon monitors endpoint activity for anomalous behavior. Network monitoring via AWS Network Firewall with Palo Alto VM-Series detects unauthorized connections. The Security Engineer reviews monitoring dashboards daily and tunes detection rules monthly per PHS-PROC-SI-004. Automated alerts notify soc@patriothealth.com within 5 minutes of detection.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-4","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-4(2)', 'implemented', 'Patriot Health Systems implements SI-4(2) for the MFEHR system. CrowdStrike Falcon and Splunk Enterprise provide defense-in-depth for system integrity. Tenable Nessus Professional validates system integrity through regular scans. The Security Engineer maintains SI controls per PHS-PROC-SI-4 and reports findings to the Sarah Rodriguez. All integrity events are logged to Splunk Enterprise for continuous monitoring.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-42","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-4(4)', 'partially_implemented', 'System and information integrity control SI-4(4) for MFEHR is partially operational. CrowdStrike Falcon provides malicious code protection and Tenable Nessus Professional performs regular vulnerability scanning across AWS GovCloud (US-East) components. Specific SI-4(4) requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in PHS-PROC-SI-001. POA&M POAM-MFEHR-2026-SI4 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-44","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-phs-001', 'fedramp-moderate', 'SI-4(5)', 'planned', 'Implementation of SI-4(5) for MFEHR is planned for completion by Q3 FY2026. Patriot Health Systems has drafted the implementation approach in PHS-PROC-SI4-PLAN and allocated resources from the DevOps Engineering Team. The planned implementation will leverage AWS GovCloud (US-East) capabilities and integrate with existing Splunk Enterprise SIEM with 365-day retention, CrowdStrike Falcon EDR on all endpoints monitoring infrastructure. This item is tracked in POA&M item POAM-MFEHR-2026-SI45 with monthly status reviews by the Sarah Rodriguez.', 'Security Engineer', NULL, NULL, NULL, 'moderate', '{"evidence":"PHS-POL-SI-001, PHS-PROC-SI-45","assessed_by":"user-phs-002","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
