-- ============================================================================
-- ForgeComply 360 Platform (FC360) — sys-001
-- ============================================================================
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-1', 'implemented', 'Forge Cyber Defense has developed and maintains Access Control Policy FCD-POL-AC-001 v4.0 governing all access to the FC360 system. The policy addresses account management, access enforcement, information flow, separation of duties, least privilege, remote access, wireless access, and mobile device controls. Procedures are documented in FCD-PROC-AC-001 v3.1. The Stanley Riley reviews and updates the policy annually, with the most recent review completed January 2026. All personnel with FC360 access acknowledge the policy during onboarding and annually thereafter.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-11', 'implemented', 'Forge Cyber Defense enforces AC-11 within the FC360 system boundary using JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app for authentication and authorization. Access control policies defined in FCD-POL-AC-001 specify requirements for AC-11. Technical enforcement is provided through Cloudflare Workers edge infrastructure (200+ global PoPs) security controls and Cloudflare WAF with managed rulesets and custom rules. The Stanley Riley monitors compliance through Cloudflare Logpush to R2 with 365-day retention dashboards and conducts quarterly access reviews per FCD-PROC-AC-REVIEW-001.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-11","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-11(1)', 'implemented', 'Forge Cyber Defense implements AC-11(1) for the FC360 system. This enhancement to AC-11 is enforced through JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app with additional technical controls provided by Cloudflare Workers edge infrastructure (200+ global PoPs). The ISSO ensures configuration compliance through Infrastructure-as-code via Wrangler with version-controlled configs. Implementation details are documented in FCD-PROC-AC-11(1) and verified during quarterly security assessments. All relevant activities are monitored by Cloudflare Logpush to R2 with 365-day retention.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-111","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-12', 'implemented', 'Forge Cyber Defense enforces AC-12 within the FC360 system boundary using JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app for authentication and authorization. Access control policies defined in FCD-POL-AC-001 specify requirements for AC-12. Technical enforcement is provided through Cloudflare Workers edge infrastructure (200+ global PoPs) security controls and Cloudflare WAF with managed rulesets and custom rules. The Stanley Riley monitors compliance through Cloudflare Logpush to R2 with 365-day retention dashboards and conducts quarterly access reviews per FCD-PROC-AC-REVIEW-001.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-12","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
