INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-2', 'implemented', 'Account management for FC360 is performed through Built-in authentication with Cloudflare Access overlay with automated provisioning and deprovisioning workflows. New accounts require supervisor approval via Linear workflow. Stanley Riley conducts access reviews every 90 days using automated reports from JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app. Accounts inactive for 45 days are automatically disabled. Terminated users are deprovisioned within 24 hours per HR integration. All account lifecycle events are logged to Cloudflare Logpush to R2 with 365-day retention for audit purposes. Emergency accounts require AO approval and are limited to 72-hour validity.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-2(1)', 'implemented', 'Forge Cyber Defense implements AC-2(1) for the FC360 system. This enhancement to AC-2 is enforced through JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app with additional technical controls provided by Cloudflare Workers edge infrastructure (200+ global PoPs). The ISSO ensures configuration compliance through Infrastructure-as-code via Wrangler with version-controlled configs. Implementation details are documented in FCD-PROC-AC-2(1) and verified during quarterly security assessments. All relevant activities are monitored by Cloudflare Logpush to R2 with 365-day retention.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-21","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-2(13)', 'partially_implemented', 'Forge Cyber Defense has partially implemented AC-2(13) for the FC360 system. Core access control mechanisms are operational through JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app, enforcing role-based access with least privilege principles. However, automated access review workflows for AC-2(13) requirements are still being configured in Linear. The Stanley Riley conducts manual quarterly reviews as an interim measure. Full automation is targeted for completion by Q3 FY2026, tracked in POA&M item POAM-FC360-2026-AC2. Current policy documentation exists in FCD-POL-AC-001 v2.1.', 'ISSO', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-213","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
