INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-22', 'implemented', 'Forge Cyber Defense enforces AC-22 within the FC360 system boundary using JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app for authentication and authorization. Access control policies defined in FCD-POL-AC-001 specify requirements for AC-22. Technical enforcement is provided through Cloudflare Workers edge infrastructure (200+ global PoPs) security controls and Cloudflare WAF with managed rulesets and custom rules. The Stanley Riley monitors compliance through Cloudflare Logpush to R2 with 365-day retention dashboards and conducts quarterly access reviews per FCD-PROC-AC-REVIEW-001.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-22","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-3', 'implemented', 'Access enforcement in FC360 uses role-based access control (RBAC) with eight defined role tiers. JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app enforces authentication requirements before granting access. Cloudflare D1 (SQLite-based, AES-256 encryption at rest) implements row-level security for data isolation between organizational units. All access decisions are logged to Cloudflare Logpush to R2 with 365-day retention. API endpoints enforce authorization checks using middleware that validates JWT claims against role permissions. Administrative access requires additional MFA step-up authentication.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-3","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AC-4', 'implemented', 'Information flow enforcement within FC360 is implemented through Cloudflare WAF with managed rulesets and custom rules rules that restrict data movement between security domains. Cloudflare Workers edge infrastructure (200+ global PoPs) network segmentation isolates federal compliance data, CUI, and system security artifacts processing from public-facing components. Data loss prevention rules in Cloudflare WAF with managed rulesets and custom rules prevent unauthorized transmission of federal compliance data, CUI, and system security artifacts. All cross-boundary data flows are logged and monitored by Cloudflare Logpush to R2 with 365-day retention.', 'ISSO', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AC-001, FCD-PROC-AC-4","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
