INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AT-1', 'implemented', 'Forge Cyber Defense maintains Security Awareness and Training Policy FCD-POL-AT-001 v3.0. The policy establishes requirements for role-based security training, annual awareness refresher training, and specialized training for personnel with significant security responsibilities within the FC360 system. The Training Manager coordinates training delivery and tracks completion through Linear. Policy is reviewed annually by the Stanley Riley.', 'Training Manager', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AT-001, FCD-PROC-AT-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AT-2', 'implemented', 'Forge Cyber Defense implements AT-2 through its comprehensive security training program documented in FCD-POL-AT-001. All FC360 users complete annual security awareness training covering federal compliance data, CUI, and system security artifacts handling, phishing recognition, and incident reporting. Role-based training is provided to system administrators, developers, and security personnel. Training completion is tracked in Linear with automated reminders for overdue training. The Training Manager reports completion metrics to the Stanley Riley monthly.', 'Training Manager', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AT-001, FCD-PROC-AT-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
