INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AU-1', 'implemented', 'Forge Cyber Defense has established Audit and Accountability Policy FCD-POL-AU-001 v3.0 for the FC360 system. The policy defines auditable events, audit record content requirements, audit storage capacity, audit review and analysis procedures, and audit record retention (365 days minimum). Procedures are documented in FCD-PROC-AU-001. The Security Engineer maintains audit infrastructure on Cloudflare Workers edge infrastructure (200+ global PoPs) with events forwarded to Cloudflare Logpush to R2 with 365-day retention.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AU-001, FCD-PROC-AU-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AU-11', 'implemented', 'Forge Cyber Defense implements AU-11 for the FC360 system. Cloudflare Logpush to R2 with 365-day retention provides centralized audit management with automated collection from Cloudflare Workers edge infrastructure (200+ global PoPs) infrastructure, Cloudflare D1 (SQLite-based, AES-256 encryption at rest) audit logs, and application event streams. Audit records include timestamp, source, event type, user identity, outcome, and affected resources. The Security Engineer reviews audit configurations quarterly per FCD-PROC-AU-001. Audit data is retained for 365 days with integrity protections.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AU-001, FCD-PROC-AU-11","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AU-12', 'implemented', 'FC360 generates audit records for all events defined in AU-2 at each processing component. Cloudflare Workers edge infrastructure (200+ global PoPs) infrastructure generates platform-level audit records. Application code generates structured audit entries for business logic events. Cloudflare D1 (SQLite-based, AES-256 encryption at rest) generates query audit logs. All audit generation is configured per FCD-PROC-AU-012 and validated monthly by the Security Engineer. Audit generation cannot be disabled without Stanley Riley approval and change control via Linear.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AU-001, FCD-PROC-AU-12","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AU-2', 'implemented', 'FC360 logs all auditable events across all system tiers: application events (authentication, authorization decisions, data access, configuration changes), infrastructure events from Cloudflare Workers edge infrastructure (200+ global PoPs), database audit logs from Cloudflare D1 (SQLite-based, AES-256 encryption at rest), and network events from Cloudflare WAF with managed rulesets and custom rules. Event types are reviewed annually and updated based on threat intelligence. All events are forwarded to Cloudflare Logpush to R2 with 365-day retention within 60 seconds for real-time correlation and alerting. The Security Engineer maintains the audit event catalog in FCD-PROC-AU-002.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AU-001, FCD-PROC-AU-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'AU-3', 'implemented', 'Forge Cyber Defense implements AU-3 for the FC360 system. Cloudflare Logpush to R2 with 365-day retention provides centralized audit management with automated collection from Cloudflare Workers edge infrastructure (200+ global PoPs) infrastructure, Cloudflare D1 (SQLite-based, AES-256 encryption at rest) audit logs, and application event streams. Audit records include timestamp, source, event type, user identity, outcome, and affected resources. The Security Engineer reviews audit configurations quarterly per FCD-PROC-AU-001. Audit data is retained for 365 days with integrity protections.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-AU-001, FCD-PROC-AU-3","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
