INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'CM-1', 'implemented', 'Forge Cyber Defense has established Configuration Management Policy FCD-POL-CM-001 v3.0 for the FC360 system. The policy covers baseline configurations, change management, security impact analysis, access restrictions for change, least functionality, and configuration settings. Infrastructure-as-code via Wrangler with version-controlled configs enforces baselines across Cloudflare Workers edge infrastructure (200+ global PoPs) infrastructure. The System Administrator maintains the CM program with Stanley Riley oversight. Procedures documented in FCD-PROC-CM-001.', 'System Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-CM-001, FCD-PROC-CM-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'CM-10', 'partially_implemented', 'Configuration management for CM-10 is partially implemented in the FC360 environment. Infrastructure-as-code via Wrangler with version-controlled configs enforces baseline configurations across managed components on Cloudflare Workers edge infrastructure (200+ global PoPs). However, automated deviation detection and remediation workflows for all CM-10 sub-requirements are still being validated. The Platform Engineering Team performs weekly manual configuration audits as a compensating measure. Full implementation is tracked in POA&M POAM-FC360-2026-CM10 with target completion Q3 FY2026.', 'System Administrator', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-CM-001, FCD-PROC-CM-10","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
