INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'CM-2', 'implemented', 'Security configuration baselines for FC360 are established and maintained using Infrastructure-as-code via Wrangler with version-controlled configs. Baselines cover Cloudflare Workers edge infrastructure (200+ global PoPs) infrastructure, Cloudflare D1 (SQLite-based, AES-256 encryption at rest) configurations, application settings, and network device configurations from Cloudflare WAF with managed rulesets and custom rules. Baseline deviations require change control approval via Linear with security impact analysis. The System Administrator reviews and updates baselines quarterly. Current baselines are documented in FCD-PROC-CM-002.', 'System Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-CM-001, FCD-PROC-CM-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
