INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'CP-9', 'implemented', 'FC360 data backups are performed automatically by Cloudflare D1 (SQLite-based, AES-256 encryption at rest) with the following schedule: full backups daily (retained 30 days), incremental backups every 6 hours, and transaction log backups every 15 minutes. Backups are encrypted using AES-256 and stored in a geographically separate region. Backup integrity is verified weekly through automated restore testing. The System Administrator monitors backup completion via Cloudflare Logpush to R2 with 365-day retention alerts.', 'Contingency Planning Coordinator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-CP-001, FCD-PROC-CP-9","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'CP-9(1)', 'partially_implemented', 'Contingency planning control CP-9(1) for FC360 is partially addressed. Core disaster recovery procedures are documented in FCD-POL-CP-001, and Cloudflare Workers edge infrastructure (200+ global PoPs) provides infrastructure-level redundancy. Testing of the full CP-9(1) requirements, including tabletop exercises and functional recovery tests, has been partially completed. The Contingency Planning Coordinator is scheduling additional tests per FCD-PROC-CP-TEST-001. POA&M POAM-FC360-2026-CP9 tracks remaining items.', 'Contingency Planning Coordinator', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-CP-001, FCD-PROC-CP-91","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'CP-9(8)', 'planned', 'Implementation of CP-9(8) for FC360 is planned for completion by Q3 FY2026. Forge Cyber Defense has drafted the implementation approach in FCD-PROC-CP9-PLAN and allocated resources from the Platform Engineering Team. The planned implementation will leverage Cloudflare Workers edge infrastructure (200+ global PoPs) capabilities and integrate with existing Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers monitoring infrastructure. This item is tracked in POA&M item POAM-FC360-2026-CP98 with monthly status reviews by the Stanley Riley.', 'Contingency Planning Coordinator', NULL, NULL, NULL, 'moderate', '{"evidence":"FCD-POL-CP-001, FCD-PROC-CP-98","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-1', 'implemented', 'Forge Cyber Defense maintains Identification and Authentication Policy FCD-POL-IA-001 v3.0 for the FC360 system. The policy establishes requirements for user identification, authenticator management, MFA, device identification, and federated identity. JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app serves as the primary identity provider. The Identity Administrator manages the IA infrastructure. Procedures documented in FCD-PROC-IA-001.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-11', 'partially_implemented', 'Identity and authentication control IA-11 for FC360 is partially implemented. JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app provides primary authentication with MFA enforcement for all privileged and non-privileged users. Specific IA-11 enhancements requiring additional identity proofing or federation capabilities are in progress. Built-in authentication with Cloudflare Access overlay configuration updates are being tested in the staging environment by the Identity Administrator. Target completion is Q3 FY2026, tracked in POA&M POAM-FC360-2026-IA11.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-11","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-12', 'implemented', 'Forge Cyber Defense implements IA-12 for the FC360 system through JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app and Built-in authentication with Cloudflare Access overlay. Authentication policies enforce password complexity (16-character minimum, no dictionary words), account lockout (5 attempts), and session management. The Identity Administrator reviews authentication configurations quarterly. All authentication events are logged to Cloudflare Logpush to R2 with 365-day retention for security monitoring.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-12","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-12(2)', 'planned', 'Implementation of IA-12(2) for FC360 is planned for completion by Q3 FY2026. Forge Cyber Defense has drafted the implementation approach in FCD-PROC-IA12-PLAN and allocated resources from the Platform Engineering Team. The planned implementation will leverage Cloudflare Workers edge infrastructure (200+ global PoPs) capabilities and integrate with existing Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers monitoring infrastructure. This item is tracked in POA&M item POAM-FC360-2026-IA122 with monthly status reviews by the Stanley Riley.', 'Identity Administrator', NULL, NULL, NULL, 'moderate', '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-122","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-12(3)', 'planned', 'Implementation of IA-12(3) for FC360 is planned for completion by Q3 FY2026. Forge Cyber Defense has drafted the implementation approach in FCD-PROC-IA12-PLAN and allocated resources from the Platform Engineering Team. The planned implementation will leverage Cloudflare Workers edge infrastructure (200+ global PoPs) capabilities and integrate with existing Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers monitoring infrastructure. This item is tracked in POA&M item POAM-FC360-2026-IA123 with monthly status reviews by the Stanley Riley.', 'Identity Administrator', NULL, NULL, NULL, 'moderate', '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-123","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-12(5)', 'planned', 'Implementation of IA-12(5) for FC360 is planned for completion by Q3 FY2026. Forge Cyber Defense has drafted the implementation approach in FCD-PROC-IA12-PLAN and allocated resources from the Platform Engineering Team. The planned implementation will leverage Cloudflare Workers edge infrastructure (200+ global PoPs) capabilities and integrate with existing Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers monitoring infrastructure. This item is tracked in POA&M item POAM-FC360-2026-IA125 with monthly status reviews by the Stanley Riley.', 'Identity Administrator', NULL, NULL, NULL, 'moderate', '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-125","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-2', 'implemented', 'All FC360 users are uniquely identified and authenticated through JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app. Network and local access requires valid credentials verified against the Built-in authentication with Cloudflare Access overlay identity store. Session tokens are cryptographically signed and expire after 8 hours of inactivity. Failed authentication attempts are logged to Cloudflare Logpush to R2 with 365-day retention and accounts are locked after 5 consecutive failures. The Identity Administrator manages user provisioning per FCD-PROC-IA-002.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-2(1)', 'implemented', 'FC360 enforces multi-factor authentication for all privileged access through JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app. Privileged users must present a valid password plus a second factor (hardware token or authenticator application) before accessing administrative functions. MFA is enforced at the Built-in authentication with Cloudflare Access overlay level and cannot be bypassed. MFA configuration is documented in FCD-PROC-IA-002-01 and audited quarterly.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-21","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IA-2(12)', 'implemented', 'Forge Cyber Defense implements IA-2(12) for the FC360 system through JWT with PBKDF2-SHA256 (100K iterations), TOTP-based MFA via authenticator app and Built-in authentication with Cloudflare Access overlay. Authentication policies enforce password complexity (16-character minimum, no dictionary words), account lockout (5 attempts), and session management. The Identity Administrator reviews authentication configurations quarterly. All authentication events are logged to Cloudflare Logpush to R2 with 365-day retention for security monitoring.', 'Identity Administrator', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-IA-001, FCD-PROC-IA-212","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
