INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IR-2', 'implemented', 'Forge Cyber Defense implements IR-2 for the FC360 system as part of its incident response program. Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers provides detection capabilities with automated alerting to incident@forgecyberdefense.com. The Incident Response Lead coordinates response activities per FCD-PROC-IR-2. Incident metrics are reported to the Stanley Riley monthly and used to improve detection and response procedures.', 'Incident Response Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-IR-001, FCD-PROC-IR-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
