INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IR-3(2)', 'planned', 'Implementation of IR-3(2) for FC360 is planned for completion by Q3 FY2026. Forge Cyber Defense has drafted the implementation approach in FCD-PROC-IR3-PLAN and allocated resources from the Platform Engineering Team. The planned implementation will leverage Cloudflare Workers edge infrastructure (200+ global PoPs) capabilities and integrate with existing Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers monitoring infrastructure. This item is tracked in POA&M item POAM-FC360-2026-IR32 with monthly status reviews by the Stanley Riley.', 'Incident Response Lead', NULL, NULL, NULL, 'moderate', '{"evidence":"FCD-POL-IR-001, FCD-PROC-IR-32","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IR-4', 'implemented', 'FC360 incident handling follows the process defined in FCD-PROC-IR-004: (1) Detection via Cloudflare Logpush to R2 with 365-day retention and CrowdStrike Falcon on development workstations automated alerts, (2) Triage by SOC analysts within 15 minutes, (3) Containment actions per severity-specific playbooks, (4) Eradication and recovery with change control, (5) Lessons learned within 5 business days. All incidents are tracked in Linear with classification per FCD-POL-IR-001. The Incident Response Lead briefs Stanley Riley on significant incidents within 1 hour.', 'Incident Response Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-IR-001, FCD-PROC-IR-4","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'IR-4(1)', 'partially_implemented', 'Incident response capability for IR-4(1) within FC360 is partially operational. Forge Cyber Defense maintains an incident response plan (FCD-POL-IR-001 v3.0) with defined procedures for detection, containment, and recovery. Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers provides real-time alerting to incident@forgecyberdefense.com. However, specific IR-4(1) requirements for automated response orchestration are still being integrated. The Incident Response Lead is coordinating with Platform Engineering Team to complete automation. POA&M POAM-FC360-2026-IR4 tracks this item.', 'Incident Response Lead', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-IR-001, FCD-PROC-IR-41","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
