INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'PE-15', 'alternative', 'Forge Cyber Defense implements an alternative control for PE-15 within the FC360 system boundary. The original control requirement is addressed through compensating controls documented in FCD-POL-ALT-PE15 and approved by the FedRAMP PMO / 3PAO. The compensating control provides equivalent or greater protection through Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers continuous monitoring and automated enforcement via Cloudflare WAF with managed rulesets and custom rules. Risk acceptance for this alternative implementation was signed by the AO on the most recent authorization date.', 'Facilities Manager', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-PE-001, FCD-PROC-PE-15","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
