INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'PS-1', 'implemented', 'Forge Cyber Defense maintains Personnel Security Policy FCD-POL-PS-001 v2.0. The policy establishes requirements for position risk designation, personnel screening, personnel termination and transfer, access agreements, third-party personnel security, and personnel sanctions. HR Security Liaison coordinates with the Stanley Riley on personnel security matters. Procedures documented in FCD-PROC-PS-001, reviewed annually.', 'HR Security Liaison', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-PS-001, FCD-PROC-PS-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'PS-2', 'implemented', 'Forge Cyber Defense implements PS-2 through its personnel security program documented in FCD-POL-PS-001. Personnel with access to FC360 and federal compliance data, CUI, and system security artifacts undergo background investigations commensurate with position risk designation. The HR Security Liaison coordinates with the Stanley Riley on access agreements, transfers, and terminations. Personnel actions affecting system access are processed within 24 hours through Linear workflows.', 'HR Security Liaison', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-PS-001, FCD-PROC-PS-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
