INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'RA-1', 'implemented', 'Forge Cyber Defense maintains Risk Assessment Policy FCD-POL-RA-001 v2.0 for the FC360 system. The policy establishes requirements for security categorization, risk assessments, vulnerability scanning, and risk response. The Risk Assessment Lead coordinates annual risk assessments with input from the Stanley Riley and system owners. Procedures documented in FCD-PROC-RA-001.', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-RA-001, FCD-PROC-RA-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'RA-2', 'implemented', 'Forge Cyber Defense implements RA-2 for the FC360 system as part of its risk management program. Risk assessments are conducted annually and upon significant system changes. Snyk for dependency scanning, Cloudflare Security Center provides technical vulnerability data, while threat intelligence from Cloudflare Logpush to R2 with 365-day retention informs risk prioritization. The Risk Assessment Lead maintains the risk register and reports findings to the Stanley Riley. Documentation maintained in FCD-PROC-RA-2.', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-RA-001, FCD-PROC-RA-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'RA-3', 'implemented', 'Forge Cyber Defense implements RA-3 for the FC360 system as part of its risk management program. Risk assessments are conducted annually and upon significant system changes. Snyk for dependency scanning, Cloudflare Security Center provides technical vulnerability data, while threat intelligence from Cloudflare Logpush to R2 with 365-day retention informs risk prioritization. The Risk Assessment Lead maintains the risk register and reports findings to the Stanley Riley. Documentation maintained in FCD-PROC-RA-3.', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-RA-001, FCD-PROC-RA-3","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'RA-3(1)', 'partially_implemented', 'Forge Cyber Defense has partially implemented RA-3(1) for the FC360 system. Core requirements are operational, with specific sub-requirements under active development. Implementation progress is tracked in POA&M item POAM-FC360-2026-RA3. The Stanley Riley reviews implementation status monthly. Policy documentation exists in FCD-POL-RA-001. Full implementation is targeted for Q3 FY2026 with Platform Engineering Team leading the technical effort on Cloudflare Workers edge infrastructure (200+ global PoPs).', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-RA-001, FCD-PROC-RA-31","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'RA-5', 'implemented', 'Vulnerability scanning for FC360 is performed using Snyk for dependency scanning, Cloudflare Security Center on the following schedule: authenticated scans of all system components weekly, web application scans monthly, and ad-hoc scans within 72 hours of new vulnerability disclosures. Scan results are correlated with threat intelligence in Cloudflare Logpush to R2 with 365-day retention. Critical vulnerabilities are remediated within 30 days, high within 90 days per FCD-PROC-RA-005. The Risk Assessment Lead reviews scan reports and tracks remediation in Linear.', 'Risk Assessment Lead', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-RA-001, FCD-PROC-RA-5","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'RA-5(11)', 'planned', 'Implementation of RA-5(11) for FC360 is planned for completion by Q3 FY2026. Forge Cyber Defense has drafted the implementation approach in FCD-PROC-RA5-PLAN and allocated resources from the Platform Engineering Team. The planned implementation will leverage Cloudflare Workers edge infrastructure (200+ global PoPs) capabilities and integrate with existing Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers monitoring infrastructure. This item is tracked in POA&M item POAM-FC360-2026-RA511 with monthly status reviews by the Stanley Riley.', 'Risk Assessment Lead', NULL, NULL, NULL, 'moderate', '{"evidence":"FCD-POL-RA-001, FCD-PROC-RA-511","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
