INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SC-1', 'implemented', 'Forge Cyber Defense maintains System and Communications Protection Policy FCD-POL-SC-001 v3.0 for the FC360 system. The policy addresses boundary protection, transmission confidentiality, cryptographic protections, denial of service protection, and session management. The Network Security Engineer implements technical controls on Cloudflare Workers edge infrastructure (200+ global PoPs) with Cloudflare WAF with managed rulesets and custom rules. Procedures documented in FCD-PROC-SC-001, reviewed annually.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SC-001, FCD-PROC-SC-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SC-10', 'implemented', 'Forge Cyber Defense implements SC-10 for the FC360 system. Cloudflare WAF with managed rulesets and custom rules and Cloudflare Workers edge infrastructure (200+ global PoPs) security features provide network-level protections. Cryptographic controls use FIPS 140-2 validated modules for federal compliance data, CUI, and system security artifacts protection. The Network Security Engineer maintains SC controls per FCD-PROC-SC-10 with configurations validated through Infrastructure-as-code via Wrangler with version-controlled configs compliance scans.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SC-001, FCD-PROC-SC-10","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
