INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SC-23', 'partially_implemented', 'Forge Cyber Defense has partially implemented SC-23 for the FC360 system. Core requirements are operational, with specific sub-requirements under active development. Implementation progress is tracked in POA&M item POAM-FC360-2026-SC23. The Stanley Riley reviews implementation status monthly. Policy documentation exists in FCD-POL-SC-001. Full implementation is targeted for Q3 FY2026 with Platform Engineering Team leading the technical effort on Cloudflare Workers edge infrastructure (200+ global PoPs).', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-SC-001, FCD-PROC-SC-23","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SC-28', 'implemented', 'FC360 protects federal compliance data, CUI, and system security artifacts at rest using Cloudflare D1 (SQLite-based, AES-256 encryption at rest) native encryption (AES-256). Encryption keys are managed through the cloud provider''s key management service with annual key rotation. Backup data is encrypted using separate encryption keys. The Network Security Engineer validates encryption configurations quarterly. Encryption status is monitored through Cloudflare Logpush to R2 with 365-day retention compliance dashboards.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SC-001, FCD-PROC-SC-28","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SC-28(1)', 'implemented', 'Forge Cyber Defense implements SC-28(1) for the FC360 system. Cloudflare WAF with managed rulesets and custom rules and Cloudflare Workers edge infrastructure (200+ global PoPs) security features provide network-level protections. Cryptographic controls use FIPS 140-2 validated modules for federal compliance data, CUI, and system security artifacts protection. The Network Security Engineer maintains SC controls per FCD-PROC-SC-28 with configurations validated through Infrastructure-as-code via Wrangler with version-controlled configs compliance scans.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SC-001, FCD-PROC-SC-281","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
