INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SC-7(8)', 'planned', 'Implementation of SC-7(8) for FC360 is planned for completion by Q3 FY2026. Forge Cyber Defense has drafted the implementation approach in FCD-PROC-SC7-PLAN and allocated resources from the Platform Engineering Team. The planned implementation will leverage Cloudflare Workers edge infrastructure (200+ global PoPs) capabilities and integrate with existing Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers monitoring infrastructure. This item is tracked in POA&M item POAM-FC360-2026-SC78 with monthly status reviews by the Stanley Riley.', 'Network Security Engineer', NULL, NULL, NULL, 'moderate', '{"evidence":"FCD-POL-SC-001, FCD-PROC-SC-78","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SC-8', 'implemented', 'FC360 protects transmitted federal compliance data, CUI, and system security artifacts using TLS 1.3 for all external communications. HSTS headers enforce encrypted connections with a minimum 1-year max-age directive. Internal service-to-service communication uses mutual TLS (mTLS) with certificate validation. Certificate management is automated through Cloudflare Workers edge infrastructure (200+ global PoPs) certificate services. The Network Security Engineer monitors certificate expiration and TLS configuration compliance via Cloudflare Logpush to R2 with 365-day retention.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SC-001, FCD-PROC-SC-8","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SC-8(1)', 'implemented', 'Forge Cyber Defense implements SC-8(1) for the FC360 system. Cloudflare WAF with managed rulesets and custom rules and Cloudflare Workers edge infrastructure (200+ global PoPs) security features provide network-level protections. Cryptographic controls use FIPS 140-2 validated modules for federal compliance data, CUI, and system security artifacts protection. The Network Security Engineer maintains SC controls per FCD-PROC-SC-8 with configurations validated through Infrastructure-as-code via Wrangler with version-controlled configs compliance scans.', 'Network Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SC-001, FCD-PROC-SC-81","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-1', 'implemented', 'Forge Cyber Defense maintains System and Information Integrity Policy FCD-POL-SI-001 v3.0 for the FC360 system. The policy covers flaw remediation, malicious code protection, information system monitoring, security alerts, software and information integrity, and spam protection. The Security Engineer implements technical controls. Procedures documented in FCD-PROC-SI-001, reviewed annually by the Stanley Riley.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-1","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-10', 'partially_implemented', 'System and information integrity control SI-10 for FC360 is partially operational. CrowdStrike Falcon on development workstations provides malicious code protection and Snyk for dependency scanning, Cloudflare Security Center performs regular vulnerability scanning across Cloudflare Workers edge infrastructure (200+ global PoPs) components. Specific SI-10 requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in FCD-PROC-SI-001. POA&M POAM-FC360-2026-SI10 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-10","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-11', 'partially_implemented', 'System and information integrity control SI-11 for FC360 is partially operational. CrowdStrike Falcon on development workstations provides malicious code protection and Snyk for dependency scanning, Cloudflare Security Center performs regular vulnerability scanning across Cloudflare Workers edge infrastructure (200+ global PoPs) components. Specific SI-11 requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in FCD-PROC-SI-001. POA&M POAM-FC360-2026-SI11 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-11","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-12', 'partially_implemented', 'System and information integrity control SI-12 for FC360 is partially operational. CrowdStrike Falcon on development workstations provides malicious code protection and Snyk for dependency scanning, Cloudflare Security Center performs regular vulnerability scanning across Cloudflare Workers edge infrastructure (200+ global PoPs) components. Specific SI-12 requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in FCD-PROC-SI-001. POA&M POAM-FC360-2026-SI12 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-12","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-16', 'implemented', 'Forge Cyber Defense implements SI-16 for the FC360 system. CrowdStrike Falcon on development workstations and Cloudflare Logpush to R2 with 365-day retention provide defense-in-depth for system integrity. Snyk for dependency scanning, Cloudflare Security Center validates system integrity through regular scans. The Security Engineer maintains SI controls per FCD-PROC-SI-16 and reports findings to the Stanley Riley. All integrity events are logged to Cloudflare Logpush to R2 with 365-day retention for continuous monitoring.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-16","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-2', 'implemented', 'Flaw remediation for FC360 follows the patching schedule in FCD-PROC-SI-002: critical patches within 30 days, high within 60 days, moderate within 90 days. Snyk for dependency scanning, Cloudflare Security Center identifies vulnerabilities and Infrastructure-as-code via Wrangler with version-controlled configs deploys patches to Cloudflare Workers edge infrastructure (200+ global PoPs) components. The Security Engineer validates patch deployment through compliance scans. Emergency patches follow the expedited change control process in Linear. Patch status is reported to the Stanley Riley weekly.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-2","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-2(2)', 'partially_implemented', 'System and information integrity control SI-2(2) for FC360 is partially operational. CrowdStrike Falcon on development workstations provides malicious code protection and Snyk for dependency scanning, Cloudflare Security Center performs regular vulnerability scanning across Cloudflare Workers edge infrastructure (200+ global PoPs) components. Specific SI-2(2) requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in FCD-PROC-SI-001. POA&M POAM-FC360-2026-SI2 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-22","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-3', 'implemented', 'Malicious code protection for FC360 is provided by CrowdStrike Falcon on development workstations deployed on all endpoints and servers. Signature updates are applied automatically within 4 hours of release. Real-time scanning covers file access, email attachments, and web downloads. CrowdStrike Falcon on development workstations behavioral analysis detects zero-day threats. Alerts are forwarded to Cloudflare Logpush to R2 with 365-day retention for correlation. The Security Engineer reviews malware detection events daily per FCD-PROC-SI-003.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-3","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-4', 'implemented', 'FC360 information system monitoring is implemented through Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers. Cloudflare Logpush to R2 with 365-day retention performs real-time event correlation with custom detection rules for federal compliance data, CUI, and system security artifacts protection scenarios. CrowdStrike Falcon on development workstations monitors endpoint activity for anomalous behavior. Network monitoring via Cloudflare WAF with managed rulesets and custom rules detects unauthorized connections. The Security Engineer reviews monitoring dashboards daily and tunes detection rules monthly per FCD-PROC-SI-004. Automated alerts notify incident@forgecyberdefense.com within 5 minutes of detection.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-4","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-4(2)', 'implemented', 'Forge Cyber Defense implements SI-4(2) for the FC360 system. CrowdStrike Falcon on development workstations and Cloudflare Logpush to R2 with 365-day retention provide defense-in-depth for system integrity. Snyk for dependency scanning, Cloudflare Security Center validates system integrity through regular scans. The Security Engineer maintains SI controls per FCD-PROC-SI-4 and reports findings to the Stanley Riley. All integrity events are logged to Cloudflare Logpush to R2 with 365-day retention for continuous monitoring.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-42","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-4(4)', 'partially_implemented', 'System and information integrity control SI-4(4) for FC360 is partially operational. CrowdStrike Falcon on development workstations provides malicious code protection and Snyk for dependency scanning, Cloudflare Security Center performs regular vulnerability scanning across Cloudflare Workers edge infrastructure (200+ global PoPs) components. Specific SI-4(4) requirements for advanced integrity verification or automated remediation are being configured. The Security Engineer is implementing additional detection rules and response playbooks. Interim manual processes are documented in FCD-PROC-SI-001. POA&M POAM-FC360-2026-SI4 tracks completion.', 'Security Engineer', '2026-01-20', '2026-02-15', 'other_than_satisfied', 'moderate', '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-44","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-4(5)', 'planned', 'Implementation of SI-4(5) for FC360 is planned for completion by Q3 FY2026. Forge Cyber Defense has drafted the implementation approach in FCD-PROC-SI4-PLAN and allocated resources from the Platform Engineering Team. The planned implementation will leverage Cloudflare Workers edge infrastructure (200+ global PoPs) capabilities and integrate with existing Cloudflare Analytics with real-time dashboards, custom SOC alerting via Workers monitoring infrastructure. This item is tracked in POA&M item POAM-FC360-2026-SI45 with monthly status reviews by the Stanley Riley.', 'Security Engineer', NULL, NULL, NULL, 'moderate', '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-45","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
INSERT OR REPLACE INTO control_implementations (org_id, system_id, framework_id, control_id, status, implementation_description, responsible_role, implementation_date, last_assessed_date, assessment_result, risk_level, metadata, created_at, updated_at) VALUES ('org_001', 'sys-001', 'fedramp-moderate', 'SI-5', 'implemented', 'Forge Cyber Defense implements SI-5 for the FC360 system. CrowdStrike Falcon on development workstations and Cloudflare Logpush to R2 with 365-day retention provide defense-in-depth for system integrity. Snyk for dependency scanning, Cloudflare Security Center validates system integrity through regular scans. The Security Engineer maintains SI controls per FCD-PROC-SI-5 and reports findings to the Stanley Riley. All integrity events are logged to Cloudflare Logpush to R2 with 365-day retention for continuous monitoring.', 'Security Engineer', '2026-01-20', '2026-02-15', 'satisfied', NULL, '{"evidence":"FCD-POL-SI-001, FCD-PROC-SI-5","assessed_by":"user-001","next_assessment":"2026-08-15"}', '2026-01-20 09:00:00', '2026-02-15 14:00:00');
